export default class OurClients {

    static get selector() {
        return '.ourClients';
    }

    constructor(el) {
        this.el = el;
        this.container = this.el.querySelector('.ourClients__container');
        this.clients = this.getClients();
        this.current = 0;
        this.timer = this.getTimer();

        this.startCarousel();

        this.active(this.clients[this.current]);
        this.setEvents();
    }

    startCarousel() {
        // Marquee CSS-only : on duplique les enfants en JS pour que
        // l'animation @keyframes translateX(-50%) boucle sans saut.
        const wrapper = this.el.querySelector('.ourClients__carouselWrapper');
        if (!wrapper) return;

        const items = Array.from(wrapper.children);
        items.forEach((item) => {
            const clone = item.cloneNode(true);
            clone.setAttribute('aria-hidden', 'true');
            wrapper.appendChild(clone);
        });

        // Active l'animation (gérée par CSS @keyframes)
        wrapper.classList.add('ourClients__carouselWrapper--marquee');
    }

    getTimer() {
        return setInterval(() => {
            this.current++;
            if (this.current >= this.clients.length) {
                this.current = 0;
            }
            this.active(this.clients[this.current]);
        }, 2000);
    }

    getClients() {
        let els = this.el.querySelectorAll('.client');
        let clients = [];

        els.forEach((el, index) => {
            let client = {};
                client.index = index;
                client.isActive = false;
                client.el = el;
            clients.push(client);
        });
        return clients;
    }

    active(client) {
        if(client.isActive) return;
        this.desactiveAll();
        this.current = client.index;
        client.isActive = true;
        client.el.classList.add('client--active');
    }

    desactive(client) {
        if(!client.isActive) return;
        client.isActive = false;
        client.el.classList.remove('client--active');
    }

    desactiveAll() {
        this.clients.forEach(client => {
            this.desactive(client);
        });
    }

    setEvents() {
        this.container.addEventListener('mouseenter', (e) => {
            clearInterval(this.timer);
        });
        
        this.clients.forEach(client => {
            client.el.addEventListener('mouseenter', (e) => {
                clearInterval(this.timer);
                this.e_enter(e, client);
            });
        });
    }


    /**
     * Handlers
     */

    e_enter(e, client) {
        this.active(client);
    }
}